export const historicoLog = pgTable("historico_log", {
	hlCodigo: integer("hl_codigo").default(sql`nextval('cod_hislog'::regclass)`).notNull(),
	logCodigo: integer("log_codigo").notNull(),
	hlHora: char("hl_hora", { length: 12 }),
	hlTabela: varchar("hl_tabela", { length: 32 }),
	hlOperacao: varchar("hl_operacao", { length: 64 }),
	hlRegistro: varchar("hl_registro", { length: 64 }),
	hlCampo: varchar("hl_campo", { length: 100 }),
	hlAntes: varchar("hl_antes", { length: 100 }),
	hlDepois: varchar("hl_depois", { length: 100 }),
	proCodigo: integer("pro_codigo"),
	forCodigo: integer("for_codigo"),
	cliCodigo: integer("cli_codigo"),
	menIndex: integer("men_index"),
	hlData: date("hl_data").default(sql`CURRENT_DATE`).notNull(),
	empCodigo: integer("emp_codigo"),
}, (table) => [
	index("historico_log_emp_codigo_idx").using("btree", table.empCodigo.asc().nullsLast().op("int4_ops")),
	index("historico_log_idx1").using("btree", table.hlRegistro.asc().nullsLast().op("text_ops")),
	index("historico_log_idx2").using("btree", table.proCodigo.asc().nullsLast().op("int4_ops")),
	index("historico_log_idx3").using("btree", table.hlData.asc().nullsLast().op("date_ops")),
	index("historico_log_log_codigo_488_idx").using("btree", table.logCodigo.asc().nullsLast().op("int4_ops")),
	index("idx_preco_venda").using("gin", table.hlCampo.asc().nullsLast().op("gin_trgm_ops")).where(sql`(upper((hl_campo)::text) ~~ '%PRE_O%VENDA%'::text)`),
	index("idx_tabela").using("btree", table.hlTabela.asc().nullsLast().op("text_ops")),
	uniqueIndex("xpkhistorico_log").using("btree", table.hlCodigo.asc().nullsLast().op("int4_ops"), table.logCodigo.asc().nullsLast().op("int4_ops")),
	foreignKey({
			columns: [table.empCodigo],
			foreignColumns: [empresa.empCodigo],
			name: "historico_log_emp_codigo_fkey"
		}),
	foreignKey({
			columns: [table.logCodigo],
			foreignColumns: [log.logCodigo],
			name: "historico_log_log_codigo_fkey_981"
		}),
]);

